class Publications extends Component {
  constructor(props) {
    super(props)
    this.state = {
      data: props.data,
      nextSortKey: 'myRank'
    }
    this.handleBtnClick = this.handleBtnClick.bind(this)
  }

  handleBtnClick() {
    // toggle the nextSortKey between year and myRank
    const nextSortKey = this.state.nextSortKey === 'year' ? 'myRank' : 'year'
    // let the parent handle re-resorting
    this.props.onSortBtnClick(this.state.nextSortKey)
    this.setState({ nextSortKey: nextSortKey })
  }

  render() {
    if (this.props.data) {
      const { data } = this.props
      return (
        <section>
          {/* <div>
            <a href='https://scholar.google.com/citations?user=s6oA5t8AAAAJ&hl=en' target='_blank' rel='noopener noreferrer'>Google Scholar</a>
          </div> */}
          <Button variant='outline-primary' onClick={this.handleBtnClick} className='my-2'>Sort by {this.state.nextSortKey}</Button>
          <ol>
            {
            data.conference.map((pub, i) => {
              return <ConferencePublication data={pub} key={i} />
            })
            }
          </ol>
        </section>
      )
    } else {
      return <ol />
    }
  }
}

export default Publications
export { Publications, ConferencePublication, JournalPublication, WorkshopPublication, parsePublication }
